def research_design_audit_gate(design):
    # D1: C-TOTALITY - ensure design is a dict
    if not isinstance(design, dict):
        return {"may_proceed": False, "reason": "Design must be a dictionary."}

    # Safely get audit_findings; default to empty list if missing or not a list
    audit_findings = design.get("audit_findings")
    if not isinstance(audit_findings, list):
        audit_findings = []

    # D4: rq_candidates must be a non-empty list
    rq_candidates = design.get("rq_candidates")
    if not isinstance(rq_candidates, list) or len(rq_candidates) == 0:
        return {"may_proceed": False, "reason": "rq_candidates must be a non-empty list."}

    # D2: Check for OPEN MAJOR findings
    has_open_major = False
    for finding in audit_findings:
        if not isinstance(finding, dict):
            continue  # Skip malformed entries
        severity = finding.get("severity")
        disposition = finding.get("disposition")
        if severity == "MAJOR" and disposition == "OPEN":
            has_open_major = True
            break

    if has_open_major:
        return {"may_proceed": False, "reason": "Found an open MAJOR audit finding."}

    # D3: Check RESOLVED findings have revision_ref
    has_resolved = False
    for finding in audit_findings:
        if not isinstance(finding, dict):
            continue  # Skip malformed entries
        if finding.get("disposition") == "RESOLVED":
            has_resolved = True
            break

    if has_resolved:
        revision_ref = design.get("revision_ref")
        if not isinstance(revision_ref, str) or len(revision_ref) == 0:
            return {"may_proceed": False, "reason": "RESOLVED findings require a non-empty revision_ref."}

    return {"may_proceed": True, "reason": "All audit gate rules satisfied."}
